import psycopg2
from psycopg2 import sql

def create_conn():
    conn = None
    try:
        conn = psycopg2.connect(host='localhost', database='hackathon_db', user='admin', password='demo123')
        
        # Create a cursor object
        cur = conn.cursor()
        
        # Execute an SQL statement using the CURSOR
        cur.execute("SELECT version();")
        
        # Fetch one row in the result set
        db_version = cur.fetchone()

        print(f'PostgreSQL database version: {db_version}')
      
    except (Exception, psycopg2.DatabaseError) as error:
        print(error)
    
    finally:
        if conn is not None:
            conn.close()

create_conn()